const int SUM_READY = 1;

#endif // MYMATH_H
// ---------------------------------------------------------------

// -- Simulated second inclusion of mymath.h ---------------------
#ifndef MYMATH_H
#define MYMATH_H

int sum(int a, int b);
const int SUM_READY = 1;

#endif // MYMATH_H
// ---------------------------------------------------------------

int sum(int a, int b) {
    return a + b;
}

int main() {
    int a{}, b{};
    std::cin >> a >> b;

    std::cout << "SUM_READY = " << SUM_READY << '\n';
    std::cout << "sum(a, b) = " << sum(a, b) << '\n';

    return 0;
}

