solution_code:
#include <iostream>

// -- Simulated first inclusion of helpers.h ---------------------
#ifndef HELPERS_H
#define HELPERS_H

const int VERSION = 2;
int square(int x);
int cube(int x);

#endif // HELPERS_H
// ---------------------------------------------------------------

// -- Simulated second inclusion of helpers.h --------------------
#ifndef HELPERS_H
#define HELPERS_H

const int VERSION = 2;
int square(int x);
int cube(int x);

#endif // HELPERS_H
// ---------------------------------------------------------------

int square(int x) {
    return x * x;
}

int cube(int x) {
    return x * x * x;
}

int main() {
    int n{};
    std::cin >> n;

    std::cout << "VERSION: " << VERSION << '\n';
    std::cout << "Square: " << square(n) << '\n';
    std::cout << "Cube: " << cube(n) << '\n';

    return 0;
}
